#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<string>v(n);char buf[20];for(int i=0;i<n;i++){scanf("%s",buf);v[i]=buf;}sort(v.begin(),v.end());bool ok=true;for(int i=1;i<n&&ok;i++){const string&a=v[i-1],&b=v[i];if(b.size()>=a.size()&&b.compare(0,a.size(),a)==0)ok=false;}printf("%s\n",ok?"YES":"NO");}
